# Let's visualize the common activation functions
import numpy as np
import matplotlib.pyplot as plt

def sigmoid(z):
    return 1 / (1 + np.exp(-z))

def tanh(z):
    return np.tanh(z)

def relu(z):
    return np.maximum(0, z)

def softplus(z):
    return np.log(1 + np.exp(z))

z = np.linspace(-5, 5, 200)
fig, ax = plt.subplots(2, 2, figsize=(10, 10))
ax[0, 0].plot(z, sigmoid(z))
ax[0, 0].set_title('Sigmoid Activation')
ax[0, 0].grid(True)

ax[0, 1].plot(z, relu(z))
ax[0, 1].set_title('ReLU Activation')
ax[0, 1].grid(True)

ax[1, 0].plot(z, tanh(z))
ax[1, 0].set_title('Tanh Activation')
ax[1, 0].grid(True)

ax[1, 1].plot(z, softplus(z))
ax[1, 1].set_title('Softplus Activation')
ax[1, 1].grid(True)

plt.show()

